export const getTechnologyBySlug = (slug: string): TechnologyDetail | undefined => {
  return technologiesData.find(t => t.slug === slug);
};

export const getAllTechnologyCategories = (): string[] => {
  return [...new Set(technologiesData.map(t => t.category))];
};
